import React from 'react';
import { motion } from 'framer-motion';
import './Hero.css';

const Hero = () => {
    return (
        <div className="hero">
            <motion.h1 
                initial={{ opacity: 0, y: -50 }} 
                animate={{ opacity: 1, y: 0 }} 
                transition={{ duration: 1 }}>
                Hello, I'm [Your Name]
            </motion.h1>
            <motion.h2 
                initial={{ opacity: 0, y: -50 }} 
                animate={{ opacity: 1, y: 0 }} 
                transition={{ duration: 1, delay: 0.5 }}>
                A Passionate Developer
            </motion.h2>
            <div className="buttons">
                <motion.a 
                    href="#projects" 
                    className="btn" 
                    initial={{ opacity: 0 }} 
                    animate={{ opacity: 1 }} 
                    transition={{ duration: 1, delay: 1 }}>
                    Projects
                </motion.a>
                <motion.a 
                    href="#contact" 
                    className="btn" 
                    initial={{ opacity: 0 }} 
                    animate={{ opacity: 1 }} 
                    transition={{ duration: 1, delay: 1.5 }}>
                    Contact
                </motion.a>
            </div>
        </div>
    );
};

export default Hero;